INSERT INTO public.spells (id, name, owner_id, source, visibility, level, school, casting_time, "range", components, duration, concentration, ritual, classes, description, higher_levels, save_type, attack_type, damage_dice, damage_type, damage_at_slot_level, damage_at_char_level, heal_dice, heal_at_slot_level, area_of_effect) VALUES
('meld-into-stone', 'Meld Into Stone', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', 'Touch', 'V, S', '8 hours', false, true, '{"Cleric"}', E'You step into a stone object or surface large enough to fully contain your body, melding yourself and all the equipment you carry with the stone for the duration. Using your movement, you step into the stone at a point you can touch. Nothing of your presence remains visible or otherwise detectable by nonmagical senses.\n\nWhile merged with the stone, you can''t see what occurs outside it, and any Wisdom (Perception) checks you make to hear sounds outside it are made with disadvantage. You remain aware of the passage of time and can cast spells on yourself while merged in the stone. You can use your movement to leave the stone where you entered it, which ends the spell. You otherwise can''t move.\n\nMinor physical damage to the stone doesn''t harm you, but its partial destruction or a change in its shape (to the extent that you no longer fit within it) expels you and deals 6d6 bludgeoning damage to you. The stone''s complete destruction (or transmutation into a different substance) expels you and deals 50 bludgeoning damage to you. If expelled, you fall prone in an unoccupied space closest to where you first entered.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('nondetection', 'Nondetection', NULL, 'srd', 'private', 3, 'Abjuration', '1 action', 'Touch', 'V, S, M (A pinch of diamond dust worth 25 gp sprinkled over the target, which the spell consumes.)', '8 hours', false, false, '{"Bard","Ranger","Wizard","Psion"}', 'For the duration, you hide a target that you touch from divination magic. The target can be a willing creature or a place or an object no larger than 10 feet in any dimension. The target can''t be targeted by any divination magic or perceived through magical scrying sensors.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('phantom-steed', 'Phantom Steed', NULL, 'srd', 'private', 3, 'Illusion', '1 minute', '30 feet', 'V, S', '1 hour', false, true, '{"Wizard"}', E'A Large quasi-real, horselike creature appears on the ground in an unoccupied space of your choice within range. You decide the creature''s appearance, but it is equipped with a saddle, bit, and bridle. Any of the equipment created by the spell vanishes in a puff of smoke if it is carried more than 10 feet away from the steed.\n\nFor the duration, you or a creature you choose can ride the steed. The creature uses the statistics for a riding horse, except it has a speed of 100 feet and can travel 10 miles in an hour, or 13 miles at a fast pace. When the spell ends, the steed gradually fades, giving the rider 1 minute to dismount. The spell ends if you use an action to dismiss it or if the steed takes any damage.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('plant-growth', 'Plant Growth', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', '150 feet', 'V, S', 'Instantaneous', false, false, '{"Bard","Druid","Ranger"}', E'This spell channels vitality into plants within a specific area. There are two possible uses for the spell, granting either immediate or long-term benefits.\n\nIf you cast this spell using 1 action, choose a point within range. All normal plants in a 100-foot radius centered on that point become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.\n\nYou can exclude one or more areas of any size within the spell''s area from being affected.\n\nIf you cast this spell over 8 hours, you enrich the land. All plants in a half-mile radius centered on a point within range become enriched for 1 year. The plants yield twice the normal amount of food when harvested.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('protection-from-energy', 'Protection From Energy', NULL, 'srd', 'private', 3, 'Abjuration', '1 action', 'Touch', 'V, S', 'Up to 1 hour', true, false, '{"Cleric","Druid","Ranger","Sorcerer","Wizard"}', 'For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('remove-curse', 'Remove Curse', NULL, 'srd', 'private', 3, 'Abjuration', '1 action', 'Touch', 'V, S', 'Instantaneous', false, false, '{"Cleric","Paladin","Warlock","Wizard"}', 'At your touch, all curses affecting one creature or object end. If the object is a cursed magic item, its curse remains, but the spell breaks its owner''s attunement to the object so it can be removed or discarded.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('revivify', 'Revivify', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', 'Touch', 'V, S, M (Diamonds worth 300gp, which the spell consumes.)', 'Instantaneous', false, false, '{"Cleric","Paladin"}', 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can''t return to life a creature that has died of old age, nor can it restore any missing body parts.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('sending', 'Sending', NULL, 'srd', 'private', 3, 'Evocation', '1 action', 'Unlimited', 'V, S, M (A short piece of fine copper wire.)', '1 round', false, false, '{"Bard","Cleric","Wizard","Psion"}', E'You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables creatures with Intelligence scores of at least 1 to understand the meaning of your message.\n\nYou can send the message across any distance and even to other planes of existence, but if the target is on a different plane than you, there is a 5 percent chance that the message doesn''t arrive.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('sleet-storm', 'Sleet Storm', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', '150 feet', 'V, S, M (A pinch of dust and a few drops of water.)', 'Up to 1 minute', true, false, '{"Druid","Sorcerer","Wizard"}', E'Until the spell ends, freezing rain and sleet fall in a 20-foot-tall cylinder with a 40-foot radius centered on a point you choose within range. The area is heavily obscured, and exposed flames in the area are doused.\n\nThe ground in the area is covered with slick ice, making it difficult terrain. When a creature enters the spell''s area for the first time on a turn or starts its turn there, it must make a dexterity saving throw. On a failed save, it falls prone.\n\nIf a creature is concentrating in the spell''s area, the creature must make a successful constitution saving throw against your spell save DC or lose concentration.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cylinder","size":40}'::jsonb),
('slow', 'Slow', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', '120 feet', 'V, S, M (A drop of molasses.)', 'Up to 1 minute', true, false, '{"Sorcerer","Wizard"}', E'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a wisdom saving throw or be affected by this spell for the duration.\n\nAn affected target''s speed is halved, it takes a -2 penalty to AC and dexterity saving throws, and it can''t use reactions. On its turn, it can use either an action or a bonus action, not both. Regardless of the creature''s abilities or magic items, it can''t make more than one melee or ranged attack during its turn.\n\nIf the creature attempts to cast a spell with a casting time of 1 action, roll a d20. On an 11 or higher, the spell doesn''t take effect until the creature''s next turn, and the creature must use its action on that turn to complete the spell. If it can''t, the spell is wasted.\n\nA creature affected by this spell makes another wisdom saving throw at the end of its turn. On a successful save, the effect ends for it.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":40}'::jsonb),
('speak-with-dead', 'Speak with Dead', NULL, 'srd', 'private', 3, 'Necromancy', '1 action', '10 feet', 'V, S, M (Burning incense.)', '10 minutes', false, false, '{"Bard","Cleric"}', E'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse must still have a mouth and can''t be undead. The spell fails if the corpse was the target of this spell within the last 10 days.\n\nUntil the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are hostile to it or it recognizes you as an enemy. This spell doesn''t return the creature''s soul to its body, only its animating spirit. Thus, the corpse can''t learn new information, doesn''t comprehend anything that has happened since it died, and can''t speculate about future events.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('speak-with-plants', 'Speak with Plants', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', 'Self', 'V, S', '10 minutes', false, false, '{"Bard","Druid","Ranger"}', E'You imbue plants within 30 feet of you with limited sentience and animation, giving them the ability to communicate with you and follow your simple commands. You can question plants about events in the spell''s area within the past day, gaining information about creatures that have passed, weather, and other circumstances.\n\nYou can also turn difficult terrain caused by plant growth (such as thickets and undergrowth) into ordinary terrain that lasts for the duration. Or you can turn ordinary terrain where plants are present into difficult terrain that lasts for the duration, causing vines and branches to hinder pursuers, for example.\n\nPlants might be able to perform other tasks on your behalf, at the GM''s discretion. The spell doesn''t enable plants to uproot themselves and move about, but they can freely move branches, tendrils, and stalks.\n\nIf a plant creature is in the area, you can communicate with it as if you shared a common language, but you gain no magical ability to influence it.\n\nThis spell can cause the plants created by the entangle spell to release a restrained creature.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('spirit-guardians', 'Spirit Guardians', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', 'Self', 'V, S, M (A holy symbol.)', 'Up to 10 minutes', true, false, '{"Cleric"}', E'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.\n\nWhen you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature''s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a wisdom saving throw. On a failed save, the creature takes 3d8 radiant damage (if you are good or neutral) or 3d8 necrotic damage (if you are evil). On a successful save, the creature takes half as much damage.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for each slot level above 3rd.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('stinking-cloud', 'Stinking Cloud', NULL, 'srd', 'private', 3, 'Conjuration', '1 action', '90 feet', 'V, S, M (A rotten egg or several skunk cabbage leaves.)', 'Up to 1 minute', true, false, '{"Bard","Sorcerer","Wizard"}', E'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration.\n\nEach creature that is completely within the cloud at the start of its turn must make a constitution saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling. Creatures that don''t need to breathe or are immune to poison automatically succeed on this saving throw.\n\nA moderate wind (at least 10 miles per hour) disperses the cloud after 4 rounds. A strong wind (at least 20 miles per hour) disperses it after 1 round.', NULL, 'CON', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('tiny-hut', 'Tiny Hut', NULL, 'srd', 'private', 3, 'Evocation', '1 minute', 'Self', 'V, S, M (A small crystal bead.)', '8 hours', false, true, '{"Bard","Wizard"}', E'A 10-foot-radius immobile dome of force springs into existence around and above you and remains stationary for the duration. The spell ends if you leave its area.\n\nNine creatures of Medium size or smaller can fit inside the dome with you. The spell fails if its area includes a larger creature or more than nine creatures. Creatures and objects within the dome when you cast this spell can move through it freely. All other creatures and objects are barred from passing through it. Spells and other magical effects can''t extend through the dome or be cast through it. The atmosphere inside the space is comfortable and dry, regardless of the weather outside.\n\nUntil the spell ends, you can command the interior to become dimly lit or dark. The dome is opaque from the outside, of any color you choose, but it is transparent from the inside.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":10}'::jsonb),
('tongues', 'Tongues', NULL, 'srd', 'private', 3, 'Divination', '1 action', 'Touch', 'V, M (A small clay model of a ziggurat.)', '1 hour', false, false, '{"Bard","Cleric","Sorcerer","Warlock","Wizard","Psion"}', 'This spell grants the creature you touch the ability to understand any spoken language it hears. Moreover, when the target speaks, any creature that knows at least one language and can hear the target understands what it says.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('vampiric-touch', 'Vampiric Touch', NULL, 'srd', 'private', 3, 'Necromancy', '1 action', 'Self', 'V, S', 'Up to 1 minute', true, false, '{"Warlock","Wizard"}', 'The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt. Until the spell ends, you can make the attack again on each of your turns as an action.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', NULL, 'melee', '3d6', 'Necrotic', '{"3":"3d6","4":"4d6","5":"5d6","6":"6d6","7":"7d6","8":"8d6","9":"9d6"}'::jsonb, NULL, NULL, NULL, NULL),
('water-breathing', 'Water Breathing', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', '30 feet', 'V, S, M (A short piece of reed or straw.)', '24 hours', false, true, '{"Druid","Ranger","Sorcerer","Wizard"}', 'This spell gives a maximum of ten willing creatures within range and you can see, the ability to breathe underwater until the end of its term. Affected creatures also retain their normal breathing pattern.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('water-walk', 'Water Walk', NULL, 'srd', 'private', 3, 'Transmutation', '1 action', '30 feet', 'V, S, M (A piece of cork.)', '1 hour', false, true, '{"Cleric","Druid","Ranger","Sorcerer"}', E'This spell grants the ability to move across any liquid surface--such as water, acid, mud, snow, quicksand, or lava--as if it were harmless solid ground (creatures crossing molten lava can still take damage from the heat). Up to ten willing creatures you can see within range gain this ability for the duration.\n\nIf you target a creature submerged in a liquid, the spell carries the target to the surface of the liquid at a rate of 60 feet per round.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('wind-wall', 'Wind Wall', NULL, 'srd', 'private', 3, 'Evocation', '1 action', '120 feet', 'V, S, M (A tiny fan and a feather of exotic origin.)', 'Up to 1 minute', true, false, '{"Druid","Ranger"}', E'A wall of strong wind rises from the ground at a point you choose within range. You can make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration.\n\nWhen the wall appears, each creature within its area must make a strength saving throw. A creature takes 3d8 bludgeoning damage on a failed save, or half as much damage on a successful one.\n\nThe strong wind keeps fog, smoke, and other gases at bay. Small or smaller flying creatures or objects can''t pass through the wall. Loose, lightweight materials brought into the wall fly upward. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and automatically miss. (Boulders hurled by giants or siege engines, and similar projectiles, are unaffected.) Creatures in gaseous form can''t pass through it.', NULL, 'STR', NULL, '3d8', 'Bludgeoning', '{"3":"3d8"}'::jsonb, NULL, NULL, NULL, '{"type":"line","size":50}'::jsonb),
('arcane-eye', 'Arcane Eye', NULL, 'srd', 'private', 4, 'Divination', '1 action', '30 feet', 'V, S, M (A bit of bat fur.)', 'Up to 1 hour', true, false, '{"Cleric","Wizard","Psion"}', E'You create an invisible, magical eye within range that hovers in the air for the duration.\n\nYou mentally receive visual information from the eye, which has normal vision and darkvision out to 30 feet. The eye can look in every direction.\n\nAs an action, you can move the eye up to 30 feet in any direction. There is no limit to how far away from you the eye can move, but it can''t enter another plane of existence. A solid barrier blocks the eye''s movement, but the eye can pass through an opening as small as 1 inch in diameter.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('banishment', 'Banishment', NULL, 'srd', 'private', 4, 'Abjuration', '1 action', '60 feet', 'V, S, M (An item distasteful to the target.)', 'Up to 1 minute', true, false, '{"Cleric","Paladin","Sorcerer","Warlock","Wizard","Psion"}', E'You attempt to send one creature that you can see within range to another plane of existence. The target must succeed on a charisma saving throw or be banished.\n\nIf the target is native to the plane of existence you''re on, you banish the target to a harmless demiplane. While there, the target is incapacitated. The target remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.\n\nIf the target is native to a different plane of existence than the one you''re on, the target is banished with a faint popping noise, returning to its home plane. If the spell ends before 1 minute has passed, the target reappears in the space it left or in the nearest unoccupied space if that space is occupied. Otherwise, the target doesn''t return.', 'When you cast this spell using a spell slot of 5th level or higher, you can target one additional creature for each slot level above 4th.', 'CHA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('black-tentacles', 'Black Tentacles', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', '90 feet', 'V, S, M (A piece of tentacle from a giant octopus or a giant squid)', 'Up to 1 minute', true, false, '{"Wizard"}', E'Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in the area into difficult terrain.\n\nWhen a creature enters the affected area for the first time on a turn or starts its turn there, the creature must succeed on a Dexterity saving throw or take 3d6 bludgeoning damage and be restrained by the tentacles until the spell ends. A creature that starts its turn in the area and is already restrained by the tentacles takes 3d6 bludgeoning damage.\n\nA creature restrained by the tentacles can use its action to make a Strength or Dexterity check (its choice) against your spell save DC. On a success, it frees itself.', NULL, 'DEX', NULL, '3d6', 'Bludgeoning', '{"4":"3d6"}'::jsonb, NULL, NULL, NULL, '{"type":"cube","size":20}'::jsonb),
('blight', 'Blight', NULL, 'srd', 'private', 4, 'Necromancy', '1 action', '30 feet', 'V, S', 'Instantaneous', false, false, '{"Druid","Sorcerer","Warlock","Wizard"}', E'Necromantic energy washes over a creature of your choice that you can see within range, draining moisture and vitality from it. The target must make a constitution saving throw. The target takes 8d8 necrotic damage on a failed save, or half as much damage on a successful one. The spell has no effect on undead or constructs.\n\nIf you target a plant creature or a magical plant, it makes the saving throw with disadvantage, and the spell deals maximum damage to it.\n\nIf you target a nonmagical plant that isn''t a creature, such as a tree or shrub, it doesn''t make a saving throw; it simply withers and dies.', 'When you cast this spell using a spell slot of 5th level of higher, the damage increases by 1d8 for each slot level above 4th.', 'CON', NULL, '8d8', 'Necrotic', '{"4":"8d8","5":"9d8","6":"10d8","7":"11d8","8":"12d8","9":"13d8"}'::jsonb, NULL, NULL, NULL, NULL),
('compulsion', 'Compulsion', NULL, 'srd', 'private', 4, 'Enchantment', '1 action', '30 feet', 'V, S', 'Up to 1 minute', true, false, '{"Bard","Psion"}', E'Creatures of your choice that you can see within range and that can hear you must make a wisdom saving throw. A target automatically succeeds on this saving throw if it can''t be charmed. On a failed save, a target is affected by this spell. Until the spell ends, you can use a bonus action on each of your turns to designate a direction that is horizontal to you. Each affected target must use as much of its movement as possible to move in that direction on its next turn. It can take any action before it moves. After moving in this way, it can make another Wisdom save to try to end the effect.\n\nA target isn''t compelled to move into an obviously deadly hazard, such as a fire or a pit, but it will provoke opportunity attacks to move in the designated direction.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('confusion', 'Confusion', NULL, 'srd', 'private', 4, 'Enchantment', '1 action', '90 feet', 'V, S, M (Three walnut shells.)', 'Up to 1 minute', true, false, '{"Bard","Druid","Sorcerer","Wizard","Psion"}', E'This spell assaults and twists creatures'' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere centered on a point you choose within range must succeed on a Wisdom saving throw when you cast this spell or be affected by it.\n\nAn affected target can''t take reactions and must roll a d10 at the start of each of its turns to determine its behavior for that turn.\n\n| d10 | Behavior |\n\n|---|---|\n\n| 1 | The creature uses all its movement to move in a random direction. To determine the direction, roll a d8 and assign a direction to each die face. The creature doesn''t take an action this turn. |\n\n| 2-6 | The creature doesn''t move or take actions this turn. |\n\n| 7-8 | The creature uses its action to make a melee attack against a randomly determined creature within its reach. If there is no creature within its reach, the creature does nothing this turn. |\n\n| 9-10 | The creature can act and move normally. |\n\nAt the end of each of its turns, an affected target can make a Wisdom saving throw. If it succeeds, this effect ends for that target.', 'When you cast this spell using a spell slot of 5th level or higher, the radius of the sphere increases by 5 feet for each slot level above 4th.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":10}'::jsonb),
('conjure-minor-elementals', 'Conjure Minor Elementals', NULL, 'srd', 'private', 4, 'Conjuration', '1 minute', '90 feet', 'V, S', 'Up to 1 hour', true, false, '{"Druid","Wizard"}', E'You summon elementals that appear in unoccupied spaces that you can see within range. You choose one the following options for what appears:\n\n- One elemental of challenge rating 2 or lower\n\n- Two elementals of challenge rating 1 or lower\n\n- Four elementals of challenge rating 1/2 or lower\n\n- Eight elementals of challenge rating 1/4 or lower.\n\nAn elemental summoned by this spell disappears when it drops to 0 hit points or when the spell ends.\n\nThe summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which has its own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.\n\nThe GM has the creatures'' statistics.', 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 6th-level slot and three times as many with an 8th-level slot.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('conjure-woodland-beings', 'Conjure Woodland Beings', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', '60 feet', 'V, S, M (One holly berry per creature summoned.)', 'Up to 1 hour', true, false, '{"Druid","Ranger"}', E'You summon fey creatures that appear in unoccupied spaces that you can see within range. Choose one of the following options for what appears:\n\n- One fey creature of challenge rating 2 or lower\n\n- Two fey creatures of challenge rating 1 or lower\n\n- Four fey creatures of challenge rating 1/2 or lower\n\n- Eight fey creatures of challenge rating 1/4 or lower\n\nA summoned creature disappears when it drops to 0 hit points or when the spell ends.\n\nThe summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which have their own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.\n\nThe GM has the creatures'' statistics.', 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 6th-level slot and three times as many with an 8th-level slot.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('control-water', 'Control Water', NULL, 'srd', 'private', 4, 'Transmutation', '1 action', '300 feet', 'V, S, M (A drop of water and a pinch of dust.)', 'Up to 10 minutes', true, false, '{"Cleric","Druid","Wizard"}', E'Until the spell ends, you control any freestanding water inside an area you choose that is a cube up to 100 feet on a side. You can choose from any of the following effects when you cast this spell. As an action on your turn, you can repeat the same effect or choose a different one.\n\n***Flood.*** You cause the water level of all standing water in the area to rise by as much as 20 feet. If the area includes a shore, the flooding water spills over onto dry land.\n\nIf you choose an area in a large body of water, you instead create a 20-foot tall wave that travels from one side of the area to the other and then crashes down. Any Huge or smaller vehicles in the wave''s path are carried with it to the other side. Any Huge or smaller vehicles struck by the wave have a 25 percent chance of capsizing.\n\nThe water level remains elevated until the spell ends or you choose a different effect. If this effect produced a wave, the wave repeats on the start of your next turn while the flood effect lasts.\n\n***Part Water.*** You cause water in the area to move apart and create a trench. The trench extends across the spell''s area, and the separated water forms a wall to either side. The trench remains until the spell ends or you choose a different effect. The water then slowly fills in the trench over the course of the next round until the normal water level is restored.\n\n***Redirect Flow.*** You cause flowing water in the area to move in a direction you choose, even if the water has to flow over obstacles, up walls, or in other unlikely directions. The water in the area moves as you direct it, but once it moves beyond the spell''s area, it resumes its flow based on the terrain conditions. The water continues to move in the direction you chose until the spell ends or you choose a different effect.\n\n***Whirlpool.*** This effect requires a body of water at least 50 feet square and 25 feet deep. You cause a whirlpool to form in the center of the area. The whirlpool forms a vortex that is 5 feet wide at the base, up to 50 feet wide at the top, and 25 feet tall. Any creature or object in the water and within 25 feet of the vortex is pulled 10 feet toward it. A creature can swim away from the vortex by making a Strength (Athletics) check against your spell save DC.\n\nWhen a creature enters the vortex for the first time on a turn or starts its turn there, it must make a strength saving throw. On a failed save, the creature takes 2d8 bludgeoning damage and is caught in the vortex until the spell ends. On a successful save, the creature takes half damage, and isn''t caught in the vortex. A creature caught in the vortex can use its action to try to swim away from the vortex as described above, but has disadvantage on the Strength (Athletics) check to do so.\n\nThe first time each turn that an object enters the vortex, the object takes 2d8 bludgeoning damage; this damage occurs each round it remains in the vortex.', NULL, 'STR', NULL, '2d8', 'Bludgeoning', '{"4":"2d8"}'::jsonb, NULL, NULL, NULL, '{"type":"cube","size":100}'::jsonb),
('death-ward', 'Death Ward', NULL, 'srd', 'private', 4, 'Abjuration', '1 action', 'Touch', 'V, S', '8 hours', false, false, '{"Cleric","Paladin"}', E'You touch a creature and grant it a measure of protection from death.\n\nThe first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends.\n\nIf the spell is still in effect when the target is subjected to an effect that would kill it instantaneously without dealing damage, that effect is instead negated against the target, and the spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('dimension-door', 'Dimension Door', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', '500 feet', 'V', 'Instantaneous', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as "200 feet straight downward" or "upward to the northwest at a 45-degree angle, 300 feet."\n\nYou can bring along objects as long as their weight doesn''t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity. The creature must be within 5 feet of you when you cast this spell.\n\nIf you would arrive in a place already occupied by an object or a creature, you and any creature traveling with you each take 4d6 force damage, and the spell fails to teleport you.', NULL, NULL, NULL, '4d6', 'Force', '{"4":"4d6"}'::jsonb, NULL, NULL, NULL, NULL),
('divination', 'Divination', NULL, 'srd', 'private', 4, 'Divination', '1 action', 'Self', 'V, S, M (Incense and a sacrificial offering appropriate to your religion, together worth at least 25gp, which the spell consumes.)', 'Instantaneous', false, true, '{"Druid"}', E'Your magic and an offering put you in contact with a god or a god''s servants. You ask a single question concerning a specific goal, event, or activity to occur within 7 days. The GM offers a truthful reply. The reply might be a short phrase, a cryptic rhyme, or an omen.\n\nThe spell doesn''t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.\n\nIf you cast the spell two or more times before finishing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The GM makes this roll in secret.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('dominate-beast', 'Dominate Beast', NULL, 'srd', 'private', 4, 'Enchantment', '1 action', '60 feet', 'V, S', 'Up to 1 minute', true, false, '{"Druid","Sorcerer"}', E'You attempt to beguile a creature that you can see within range. It must succeed on a wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw.\n\nWhile the creature is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as "Attack that creature," "Run over there," or "Fetch that object." If the creature completes the order and doesn''t receive further direction from you, it defends and preserves itself to the best of its ability.\n\nYou can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn''t do anything that you don''t allow it to do. During this time, you can also cause the creature to use a reaction, but this requires you to use your own reaction as well. Each time the target takes damage, it makes a new wisdom saving throw against the spell. If the saving throw succeeds, the spell ends.', 'When you cast this spell with a 9th level spell slot, the duration is concentration, up to 8 hours.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('fabricate', 'Fabricate', NULL, 'srd', 'private', 4, 'Transmutation', '10 minutes', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Wizard"}', E'You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, and clothes from flax or wool.\n\nChoose raw materials that you can see within range. You can fabricate a Large or smaller object (contained within a 10-foot cube, or eight connected 5-foot cubes), given a sufficient quantity of raw material. If you are working with metal, stone, or another mineral substance, however, the fabricated object can be no larger than Medium (contained within a single 5-foot cube). The quality of objects made by the spell is commensurate with the quality of the raw materials.\n\nCreatures or magic items can''t be created or transmuted by this spell. You also can''t use it to create items that ordinarily require a high degree of craftsmanship, such as jewelry, weapons, glass, or armor, unless you have proficiency with the type of artisan''s tools used to craft such objects.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('faithful-hound', 'Faithful Hound', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', '30 feet', 'V, S, M (A tiny silver whistle, a piece of bone, and a thread)', '8 hours', false, false, '{"Wizard"}', E'You conjure a phantom watchdog in an unoccupied space that you can see within range, where it remains for the duration, until you dismiss it as an action, or until you move more than 100 feet away from it.\n\nThe hound is invisible to all creatures except you and can''t be harmed. When a Small or larger creature comes within 30 feet of it without first speaking the password that you specify when you cast this spell, the hound starts barking loudly. The hound sees invisible creatures and can see into the Ethereal Plane. It ignores illusions.\n\nAt the start of each of your turns, the hound attempts to bite one creature within 5 feet of it that is hostile to you. The hound''s attack bonus is equal to your spellcasting ability modifier + your proficiency bonus. On a hit, it deals 4d8 piercing damage.', NULL, NULL, 'melee', '4d8', 'Piercing', '{"4":"4d8"}'::jsonb, NULL, NULL, NULL, NULL),
('fire-shield', 'Fire Shield', NULL, 'srd', 'private', 4, 'Evocation', '1 action', 'Self', 'V, S, M (A little phosphorus or a firefly.)', '10 minutes', false, false, '{"Wizard"}', E'Thin and vaporous flame surround your body for the duration of the spell, radiating a bright light bright light in a 10-foot radius and dim light for an additional 10 feet. You can end the spell using an action to make it disappear.\n\nThe flames are around you a heat shield or cold, your choice. The heat shield gives you cold damage resistance and the cold resistance to fire damage.\n\nIn addition, whenever a creature within 5 feet of you hits you with a melee attack, flames spring from the shield. The attacker then suffers 2d8 points of fire damage or cold, depending on the model.', NULL, NULL, NULL, '2d8', 'Fire', '{"4":"2d8"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":5}'::jsonb),
('freedom-of-movement', 'Freedom of Movement', NULL, 'srd', 'private', 4, 'Abjuration', '1 action', 'Touch', 'V, S, M (A leather strap, bound around the arm or a similar appendage.)', '1 hour', false, false, '{"Bard","Cleric","Druid","Ranger","Psion"}', E'You touch a willing creature. For the duration, the target''s movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target''s speed nor cause the target to be paralyzed or restrained.\n\nThe target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled. Finally, being underwater imposes no penalties on the target''s movement or attacks.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('giant-insect', 'Giant Insect', NULL, 'srd', 'private', 4, 'Transmutation', '1 action', '30 feet', 'V, S', 'Up to 10 minutes', true, false, '{"Druid"}', E'You transform up to ten centipedes, three spiders, five wasps, or one scorpion within range into giant versions of their natural forms for the duration. A centipede becomes a giant centipede, a spider becomes a giant spider, a wasp becomes a giant wasp, and a scorpion becomes a giant scorpion.\n\nEach creature obeys your verbal commands, and in combat, they act on your turn each round. The GM has the statistics for these creatures and resolves their actions and movement.\n\nA creature remains in its giant size for the duration, until it drops to 0 hit points, or until you use an action to dismiss the effect on it.\n\nThe GM might allow you to choose different targets. For example, if you transform a bee, its giant version might have the same statistics as a giant wasp.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('greater-invisibility', 'Greater Invisibility', NULL, 'srd', 'private', 4, 'Illusion', '1 action', 'Touch', 'V, S', 'Up to 1 minute', true, false, '{"Bard","Sorcerer","Wizard","Psion"}', 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target''s person.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('guardian-of-faith', 'Guardian of Faith', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', '30 feet', 'V', '8 hours', false, false, '{"Cleric"}', E'A Large spectral guardian appears and hovers for the duration in an unoccupied space of your choice that you can see within range. The guardian occupies that space and is indistinct except for a gleaming sword and shield emblazoned with the symbol of your deity.\n\nAny creature hostile to you that moves to a space within 10 feet of the guardian for the first time on a turn must succeed on a dexterity saving throw. The creature takes 20 radiant damage on a failed save, or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.', NULL, 'DEX', NULL, '20', 'Radiant', '{"4":"20"}'::jsonb, NULL, NULL, NULL, '{"type":"cylinder","size":10}'::jsonb),
('hallucinatory-terrain', 'Hallucinatory Terrain', NULL, 'srd', 'private', 4, 'Illusion', '10 minutes', '300 feet', 'V, S, M (A stone, a twig, and a bit of green plant.)', '24 hours', false, false, '{"Bard","Druid","Warlock","Wizard","Psion"}', E'You make natural terrain in a 150-foot cube in range look, sound, and smell like some other sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road. Manufactured structures, equipment, and creatures within the area aren''t changed in appearance.\n\nThe tactile characteristics of the terrain are unchanged, so creatures entering the area are likely to see through the illusion. If the difference isn''t obvious by touch, a creature carefully examining the illusion can attempt an Intelligence (Investigation) check against your spell save DC to disbelieve it. A creature who discerns the illusion for what it is, sees it as a vague image superimposed on the terrain.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":150}'::jsonb),
('ice-storm', 'Ice Storm', NULL, 'srd', 'private', 4, 'Evocation', '1 action', '300 feet', 'V, S, M (A pinch of dust and a few drops of water.)', 'Instantaneous', false, false, '{"Druid","Sorcerer","Wizard"}', E'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one.\n\nHailstones turn the storm''s area of effect into difficult terrain until the end of your next turn.', 'When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.', 'DEX', NULL, '2d8 + 4d6', 'Bludgeoning', '{"4":"2d8 + 4d6","5":"3d8 + 4d6","6":"4d8 + 4d6","7":"5d8 + 4d6","8":"6d8 + 4d6","9":"7d8 + 4d6"}'::jsonb, NULL, NULL, NULL, '{"type":"cylinder","size":20}'::jsonb),
('locate-creature', 'Locate Creature', NULL, 'srd', 'private', 4, 'Divination', '1 action', 'Self', 'V, S, M (A bit of fur from a bloodhound.)', 'Up to 1 hour', true, false, '{"Bard","Cleric","Druid","Paladin","Ranger","Wizard","Psion"}', E'Describe or name a creature that is familiar to you. You sense the direction to the creature''s location, as long as that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement.\n\nThe spell can locate a specific creature known to you, or the nearest creature of a specific kind (such as a human or a unicorn), so long as you have seen such a creature up close--within 30 feet--at least once. If the creature you described or named is in a different form, such as being under the effects of a polymorph spell, this spell doesn''t locate the creature.\n\nThis spell can''t locate a creature if running water at least 10 feet wide blocks a direct path between you and the creature.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('phantasmal-killer', 'Phantasmal Killer', NULL, 'srd', 'private', 4, 'Illusion', '1 action', '120 feet', 'V, S', 'Up to 1 minute', true, false, '{"Wizard","Psion"}', 'You tap into the nightmares of a creature you can see within range and create an illusory manifestation of its deepest fears, visible only to that creature. The target must make a wisdom saving throw. On a failed save, the target becomes frightened for the duration. At the start of each of the target''s turns before the spell ends, the target must succeed on a wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends.', 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d10 for each slot level above 4th.', 'WIS', NULL, '4d10', 'Psychic', '{"4":"4d10"}'::jsonb, NULL, NULL, NULL, NULL),
('polymorph', 'Polymorph', NULL, 'srd', 'private', 4, 'Transmutation', '1 action', '60 feet', 'V, S, M (A caterpillar cocoon.)', 'Up to 1 hour', true, false, '{"Bard","Druid","Sorcerer","Wizard","Psion"}', E'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a wisdom saving throw to avoid the effect. A shapechanger automatically succeeds on this saving throw.\n\nThe transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target''s (or the target''s level, if it doesn''t have a challenge rating). The target''s game statistics, including mental ability scores, are replaced by the statistics of the chosen beast. It retains its alignment and personality.\n\nThe target assumes the hit points of its new form. When it reverts to its normal form, the creature returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious.\n\nThe creature is limited in the actions it can perform by the nature of its new form, and it can''t speak, cast spells, or take any other action that requires hands or speech.\n\nThe target''s gear melds into the new form. The creature can''t activate, use, wield, or otherwise benefit from any of its equipment.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('private-sanctum', 'Private Sanctum', NULL, 'srd', 'private', 4, 'Abjuration', '10 minutes', '120 feet', 'V, S, M (A thin sheet of lead, a piece of opaque glass, a wad of cotton or cloth, and powdered chrysolite.)', '24 hours', false, false, '{"Wizard"}', E'You make an area within range magically secure. The area is a cube that can be as small as 5 feet to as large as 100 feet on each side. The spell lasts for the duration or until you use an action to dismiss it.\n\nWhen you cast the spell, you decide what sort of security the spell provides, choosing any or all of the following properties:\n\n- Sound can''t pass through the barrier at the edge of the warded area.\n\n- The barrier of the warded area appears dark and foggy, preventing vision (including darkvision) through it.\n\n- Sensors created by divination spells can''t appear inside the protected area or pass through the barrier at its perimeter.\n\n- Creatures in the area can''t be targeted by divination spells.\n\n- Nothing can teleport into or out of the warded area.\n\n- Planar travel is blocked within the warded area.\n\nCasting this spell on the same spot every day for a year makes this effect permanent.', 'When you cast this spell using a spell slot of 5th level or higher, you can increase the size of the cube by 100 feet for each slot level beyond 4th. Thus you could protect a cube that can be up to 200 feet on one side by using a spell slot of 5th level.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"cube","size":100}'::jsonb),
('resilient-sphere', 'Resilient Sphere', NULL, 'srd', 'private', 4, 'Evocation', '1 action', '30 feet', 'V, S, M (A hemispherical piece of clear crystal and a matching hemispherical piece of gum arabic.)', 'Up to 1 minute', true, false, '{"Wizard"}', E'A sphere of shimmering force encloses a creature or object of Large size or smaller within range. An unwilling creature must make a dexterity saving throw. On a failed save, the creature is enclosed for the duration.\n\nNothing--not physical objects, energy, or other spell effects--can pass through the barrier, in or out, though a creature in the sphere can breathe there. The sphere is immune to all damage, and a creature or object inside can''t be damaged by attacks or effects originating from outside, nor can a creature inside the sphere damage anything outside it.\n\nThe sphere is weightless and just large enough to contain the creature or object inside. An enclosed creature can use its action to push against the sphere''s walls and thus roll the sphere at up to half the creature''s speed. Similarly, the globe can be picked up and moved by other creatures.\n\nA disintegrate spell targeting the globe destroys it without harming anything inside it.', NULL, 'DEX', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('secret-chest', 'Secret Chest', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', 'Touch', 'V, S, M (An exquisite chest, 3 feet by 2 feet by 2 feet, constructed from rare materials worth at least 5,000 gp, and a Tiny replica made from the same materials worth at least 50 gp.)', 'Instantaneous', false, false, '{"Wizard"}', E'You hide a chest, and all its contents, on the Ethereal Plane. You must touch the chest and the miniature replica that serves as a material component for the spell. The chest can contain up to 12 cubic feet of nonliving material (3 feet by 2 feet by 2 feet).\n\nWhile the chest remains on the Ethereal Plane, you can use an action and touch the replica to recall the chest. It appears in an unoccupied space on the ground within 5 feet of you. You can send the chest back to the Ethereal Plane by using an action and touching both the chest and the replica.\n\nAfter 60 days, there is a cumulative 5 percent chance per day that the spell''s effect ends. This effect ends if you cast this spell again, if the smaller replica chest is destroyed, or if you choose to end the spell as an action. If the spell ends and the larger chest is on the Ethereal Plane, it is irretrievably lost.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('steel-wind-strike', 'Steel Wind Strike', NULL, 'srd', 'private', 5, 'Conjuration', '1 action', '30 feet', 'S, M (A melee weapon worth at least 1 sp)', 'Instantaneous', false, false, '{"Psion","Ranger","Wizard"}', E'You flourish the weapon used in the casting and then vanish to strike like the wind. Choose up to five creatures you can see within range. Make a melee spell attack against each target. On a hit, a target takes 6d10 force damage.\n\nYou can then teleport to an unoccupied space you can see within 5 feet of one of the targets you hit or missed.', NULL, NULL, 'melee', '6d10', 'Force', NULL, NULL, NULL, NULL, NULL),
('stone-shape', 'Stone Shape', NULL, 'srd', 'private', 4, 'Transmutation', '1 action', 'Touch', 'V, S, M (Soft clay, to be crudely worked into the desired shape for the stone object.)', 'Instantaneous', false, false, '{"Cleric","Druid","Wizard"}', 'You touch a stone object of Medium size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape that suits your purpose. So, for example, you could shape a large rock into a weapon, idol, or coffer, or make a small passage through a wall, as long as the wall is less than 5 feet thick. You could also shape a stone door or its frame to seal the door shut. The object you create can have up to two hinges and a latch, but finer mechanical detail isn''t possible.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL)
